  1	import React from 'react';
  2	import { FC, useState } from 'react';
  3	
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import { deleteNetworkInterface } from '@kubevirt-utils/components/NetworkInterfaceModal/utils/helpers';
  8	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
  9	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
 10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 11	import { NetworkPresentation } from '@kubevirt-utils/resources/vm/utils/network/constants';
 12	import {
 13	  Alert,
 14	  AlertVariant,
 15	  ButtonVariant,
 16	  Dropdown,
 17	  DropdownItem,
 18	  DropdownList,
 19	} from '@patternfly/react-core';
 20	import { isRunning } from '@virtualmachines/utils';
 21	
 22	import VirtualMachinesEditNetworkInterfaceModal from '../modal/VirtualMachinesEditNetworkInterfaceModal';
 23	
 24	type NetworkInterfaceActionsProps = {
 25	  nicName: string;
 26	  nicPresentation: NetworkPresentation;
 27	  vm: V1VirtualMachine;
 28	};
 29	
 30	const NetworkInterfaceActions: FC<NetworkInterfaceActionsProps> = ({
 31	  nicName,
 32	  nicPresentation,
 33	  vm,
 34	}) => {
 35	  const { t } = useKubevirtTranslation();
 36	  const { createModal } = useModal();
 37	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 38	  const deleteModalHeader = t('Delete NIC?');
 39	  const editBtnText = t('Edit');
 40	  const deleteBtnText = t('Delete');
 41	
 42	  const isHotPlugNIC = Boolean(nicPresentation?.iface?.bridge);
 43	
 44	  const onEditModalOpen = () => {
 45	    createModal(({ isOpen, onClose }) => (
 46	      <VirtualMachinesEditNetworkInterfaceModal
 47	        isOpen={isOpen}
 48	        nicPresentation={nicPresentation}
 49	        onClose={onClose}
 50	        vm={vm}
 51	      />
 52	    ));
 53	    setIsDropdownOpen(false);
 54	  };
 55	
 56	  const onDeleteModalOpen = () => {
 57	    createModal(({ isOpen, onClose }) => (
 58	      <TabModal<V1VirtualMachine>
 59	        headerText={deleteModalHeader}
 60	        isOpen={isOpen}
 61	        onClose={onClose}
 62	        onSubmit={() => deleteNetworkInterface(vm, nicName, nicPresentation)}
 63	        submitBtnText={deleteBtnText}
 64	        submitBtnVariant={ButtonVariant.danger}
 65	      >
 66	        <span>
 67	          {isRunning(vm) && isHotPlugNIC && (
 68	            <Alert
 69	              title={t(
 70	                'Deleting a network interface is supported only on VirtualMachines that were created in versions greater than 4.13.',
 71	              )}
 72	              component={'h6'}
 73	              isInline
 74	              variant={AlertVariant.warning}
 75	            />
 76	          )}
 77	          <br />
 78	          <ConfirmActionMessage
 79	            obj={{ metadata: { name: nicName, namespace: vm?.metadata?.namespace } }}
 80	          />
 81	        </span>
 82	      </TabModal>
 83	    ));
 84	    setIsDropdownOpen(false);
 85	  };
 86	
 87	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
 88	  return (
 89	    <Dropdown
 90	      toggle={KebabToggle({
 91	        id: 'toggle-id-6',
 92	        isExpanded: isDropdownOpen,
 93	        onClick: onToggle,
 94	      })}
 95	      isOpen={isDropdownOpen}
 96	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
 97	      onSelect={() => setIsDropdownOpen(false)}
 98	      popperProps={{ position: 'right' }}
 99	    >
100	      <DropdownList>
101	        <DropdownItem key="network-interface-edit" onClick={onEditModalOpen}>
102	          {editBtnText}
103	        </DropdownItem>
104	        <DropdownItem key="network-interface-delete" onClick={onDeleteModalOpen}>
105	          {deleteBtnText}
106	        </DropdownItem>
107	      </DropdownList>
108	    </Dropdown>
109	  );
110	};
111	
112	export default NetworkInterfaceActions;

